const TYPE_COLORS = {
  volo:       { bg:"#1a3a5c", accent:"#4a9eff", icon:"✈" },
  hotel:      { bg:"#1a3d1a", accent:"#4caf50", icon:"🏨" },
  auto:       { bg:"#3d2a1a", accent:"#ff9800", icon:"🚗" },
  parcheggio: { bg:"#2a1a3d", accent:"#9c27b0", icon:"🅿️" },
};
const COMPANY_COLORS = {
  "Ryanair":"#073590","EasyJet":"#ff6600","Wizz":"#c6007e",
  "Vueling":"#c8a800","TAP":"#006600","Air Europa":"#003087",
  "Iberia":"#d4001a","Transavia":"#00a0c8",
};

const COMPANY_URLS = {
  "Ryanair":    "https://www.ryanair.com/it/it/manage-my-booking",
  "EasyJet":    "https://www.easyjet.com/it",
  "Wizz":       "https://wizzair.com/it-it/bookings/manage-booking",
  "Vueling":    "https://www.vueling.com/it/servizi-per-i-viaggiatori/gestisci-il-tuo-volo",
  "TAP":        "https://www.tapairportugal.com/it",
  "Air Europa": "https://www.aireuropa.com/it/voli/gestisci-la-tua-prenotazione",
  "Iberia":     "https://www.iberia.com/it/gestisci/",
  "Transavia":  "https://www.transavia.com/it-IT/manage-your-booking/",
};

// Deep link: apre l'app se installata, altrimenti il sito web
const COMPANY_DEEPLINKS = {
  "Ryanair":    "ryanair://",
  "EasyJet":    "easyjet://",
  "Wizz":       "wizzair://",
  "Vueling":    "vueling://",
  "Iberia":     "iberia://",
};

function openAirlineApp(company) {
  var deeplink = COMPANY_DEEPLINKS[company];
  var weburl = COMPANY_URLS[company];
  if (deeplink) {
    // Prova ad aprire l'app, se fallisce dopo 500ms apre il sito
    var start = Date.now();
    window.location.href = deeplink;
    setTimeout(function() {
      if (Date.now() - start < 1000 && weburl) {
        window.open(weburl, "_blank");
      }
    }, 500);
  } else if (weburl) {
    window.open(weburl, "_blank");
  }
}

// ── Helpers ───────────────────────────────────────────────
function buildPDFData(personId, allBookings, eventNotes) {
  var mine = allBookings.filter(function(b) { return b.person === personId; });
  var evIds = [];
  mine.forEach(function(b) { if (!evIds.includes(b.event)) evIds.push(b.event); });
  return evIds.map(function(evId) {
    var ev = EVENTS.find(function(e) { return e.id === evId; });
    var evB = mine.filter(function(b) { return b.event === evId; });
    return {
      eventLabel: ev ? ev.label : evId,
      circuit: ev ? ev.circuit : "",
      dates: ev ? ev.dates : "",
      note: eventNotes[personId + "_" + evId] || "",
      voli: evB.filter(function(b) { return b.type === "volo"; }),
      hotels: evB.filter(function(b) { return b.type === "hotel"; }),
      autos: evB.filter(function(b) { return b.type === "auto" || b.type === "parcheggio"; }),
    };
  });
}

// ── BookingCard ───────────────────────────────────────────
function BookingCard({ b, compact, showPerson, onEdit, onDelete }) {
  var tc = TYPE_COLORS[b.type] || TYPE_COLORS.volo;
  var cc = b.company ? COMPANY_COLORS[b.company] : null;
  var person = showPerson ? PEOPLE.find(function(p) { return p.id === b.person; }) : null;

  // Check if flight has already landed
  var flightPast = false;
  if (b.type === "volo" && b.arr) {
    try {
      // Parse arr time like "BCN 13:35" → extract HH:MM
      var arrMatch = b.arr.match(/(\d{1,2}):(\d{2})$/);
      if (arrMatch) {
        var now = new Date();
        var arrTime = new Date(now.getFullYear(), now.getMonth(), now.getDate(), parseInt(arrMatch[1]), parseInt(arrMatch[2]));
        // If date field contains day info, try to use it
        // Simple check: if current time > arr time today, mark as past
        flightPast = now > arrTime;
      }
    } catch(e) {}
  }
  return (
    <div onClick={function(e){if(!e.target.closest("button")&&!e.target.closest("a")){if(typeof window.__showBookingDetail==="function") window.__showBookingDetail(b);}}}
      style={{background:tc.bg+"44",border:"1px solid "+tc.accent+"33",borderLeft:"3px solid "+(flightPast?"#444":tc.accent),borderRadius:8,padding:compact?"8px 12px":"12px 16px",marginBottom:8,display:"flex",flexWrap:"wrap",gap:8,alignItems:"center",position:"relative",opacity:flightPast?0.5:1,cursor:"pointer"}}>
      <span style={{fontSize:16}}>{tc.icon}{flightPast?" ✓":""}</span>
      {showPerson && person && <span style={{fontWeight:700,fontSize:12,color:tc.accent,minWidth:80}}>{person.name}</span>}
      {b.type === "volo" && (
        <span style={{display:"contents"}}>
          {b.company && (
            (COMPANY_URLS[b.company] || COMPANY_DEEPLINKS[b.company])
              ? <span onClick={function(e){e.stopPropagation(); openAirlineApp(b.company);}}
                  style={{background:cc||"#333",color:"#fff",borderRadius:4,padding:"1px 7px",fontSize:10,fontWeight:700,cursor:"pointer"}}>
                  🌐 {b.company}
                </span>
              : <span style={{background:cc||"#333",color:"#fff",borderRadius:4,padding:"1px 7px",fontSize:10,fontWeight:700}}>{b.company}</span>
          )}
          {b.flight && <span style={{fontWeight:700,fontSize:12}}>{b.flight}</span>}
          {(b.dep||b.arr) && <span style={{fontSize:12,color:"#b0c0e0"}}>{b.dep}{!flightPast && b.arr ? " → "+b.arr : ""}</span>}
          {b.date && <span style={{fontSize:11,color:"#7090c0"}}>{b.date}</span>}
          {b.dir && <span style={{background:b.dir==="andata"?"#1e3a8a":"#1a4a1a",color:b.dir==="andata"?"#4a9eff":"#4caf50",borderRadius:4,padding:"1px 7px",fontSize:10,fontWeight:700}}>{b.dir==="andata"?"↗ ANDATA":"↙ RITORNO"}</span>}
          {b.baggage && <span style={{fontSize:10,color:"#7090c0"}}>🧳 {b.baggage}</span>}
          {b.booking && <span style={{fontSize:10,color:"#ff9800",fontFamily:"monospace"}}>#{b.booking}</span>}
        </span>
      )}
      {b.type === "hotel" && (
        <span style={{display:"contents"}}>
          {b.address
            ? <span onClick={function(e){e.stopPropagation(); window.open("https://www.google.com/maps/search/?api=1&query="+encodeURIComponent((b.hotel||"")+" "+b.address),"_blank");}}
                style={{fontWeight:700,fontSize:12,cursor:"pointer",color:"#4caf50",textDecoration:"underline dotted"}}>
                📍 {b.hotel}
              </span>
            : <span style={{fontWeight:700,fontSize:12}}>{b.hotel}</span>
          }
          {b.room && <span style={{fontSize:11,color:"#7090c0"}}>{b.room}</span>}
          {b.nights && <span style={{fontSize:11,color:"#7090c0"}}>{b.nights} notti</span>}
          {b.booking && <span style={{fontSize:10,color:"#ff9800",fontFamily:"monospace"}}>#{b.booking}</span>}
        </span>
      )}
      {(b.type === "auto" || b.type === "parcheggio") && (
        <span style={{display:"contents"}}>
          <span style={{fontWeight:700,fontSize:12}}>{b.car}</span>
          {b.booking && b.booking !== "-" && <span style={{fontSize:10,color:"#ff9800",fontFamily:"monospace"}}>#{b.booking}</span>}
        </span>
      )}
      {b.notes && <span style={{fontSize:10,color:"#c0a060",fontStyle:"italic",width:"100%",paddingLeft:24}}>📌 {b.notes}</span>}
      {b.status && b.status !== "confermata" && (
        <span style={{fontSize:10,fontWeight:700,borderRadius:4,padding:"1px 7px",
          background:b.status==="cancellata"?"#3a0a0a":b.status==="da_confermare"?"#3a2a00":"#1a3a1a",
          color:b.status==="cancellata"?"#ff6060":b.status==="da_confermare"?"#ffcc00":"#4caf50",
          width:"100%",display:"block",marginTop:2}}>
          {b.status==="cancellata"?"❌ Cancellata":b.status==="da_confermare"?"⏳ Da confermare":"✅ Confermata"}
        </span>
      )}
      {(onEdit || onDelete) && (
        <div style={{position:"absolute",right:6,top:"50%",transform:"translateY(-50%)",display:"flex",gap:4}}>
          {onEdit && <button onClick={function() { onEdit(b); }} style={{background:"none",border:"1px solid #1e3a8a44",color:"#4a9eff",borderRadius:4,padding:"2px 7px",cursor:"pointer",fontSize:10}} onMouseEnter={function(e){e.currentTarget.style.opacity=1;}} onMouseLeave={function(e){e.currentTarget.style.opacity=0.5;}}>✏️</button>}
          {onDelete && <button onClick={function(e) { e.stopPropagation(); onDelete(b); }} style={{background:"none",border:"1px solid #ff444433",color:"#ff6060",borderRadius:4,padding:"2px 7px",cursor:"pointer",fontSize:10}}>🗑️</button>}
        </div>
      )}
    </div>
  );
}

// ── EditModal ─────────────────────────────────────────────
function EditModal({ booking, onSave, onClose, onDelete, onDuplicate }) {
  var [form, setForm] = useState(Object.assign({}, booking));
  var [showDuplicate, setShowDuplicate] = useState(false);
  var [dupPeople, setDupPeople] = useState([]);
  var fields = booking.type === "volo"
    ? [["flight","N° Volo"],["company","Compagnia"],["dep","Partenza"],["arr","Arrivo"],["date","Data"],["baggage","Bagaglio"],["booking","N° Prenotazione"],["price","Prezzo (€)"],["notes","Note"]]
    : booking.type === "hotel"
    ? [["hotel","Hotel"],["address","Indirizzo (per Maps)"],["room","Camera"],["nights","Notti"],["booking","N° Prenotazione"],["price","Prezzo (€)"],["notes","Note"]]
    : [["car","Veicolo"],["booking","N° Prenotazione"],["price","Prezzo (€)"],["notes","Note"]];
  var statusOptions = [{v:"confermata",l:"✅ Confermata"},{v:"da_confermare",l:"⏳ Da confermare"},{v:"cancellata",l:"❌ Cancellata"}];
  var ev = EVENTS.find(function(e) { return e.id === booking.event; });
  var inp = {width:"100%",padding:"8px 10px",background:"#0d0d1a",border:"1px solid #1e3a8a",borderRadius:6,color:"#e8e8f0",fontSize:13,boxSizing:"border-box",outline:"none"};
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.8)",zIndex:2000,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{background:"#12121f",borderRadius:14,padding:24,width:480,maxWidth:"100%",border:"1px solid #1e3a8a",maxHeight:"90vh",overflowY:"auto"}}>
        <div style={{fontWeight:800,fontSize:16,marginBottom:20,color:"#4a9eff"}}>✏️ Modifica — {ev ? ev.label : booking.event}</div>
        {fields.map(function(pair) {
          var key = pair[0], label = pair[1];
          return (
            <div key={key} style={{marginBottom:12}}>
              <label style={{fontSize:11,color:"#7090c0",display:"block",marginBottom:4}}>{label}</label>
              {key === "notes"
                ? <textarea value={form[key]||""} onChange={function(e){setForm(function(f){var n=Object.assign({},f);n[key]=e.target.value;return n;});}} style={Object.assign({},inp,{resize:"vertical",minHeight:60})}/>
                : <input value={form[key]||""} onChange={function(e){setForm(function(f){var n=Object.assign({},f);n[key]=e.target.value;return n;});}} style={inp}/>
              }
            </div>
          );
        })}
        <div style={{marginBottom:12,marginTop:4}}>
          <label style={{fontSize:11,color:"#7090c0",display:"block",marginBottom:6,fontWeight:600}}>Stato prenotazione</label>
          <div style={{display:"flex",gap:6}}>
            {statusOptions.map(function(opt){
              var sel=(form.status||"confermata")===opt.v;
              return (
                <button key={opt.v} onClick={function(){setForm(function(f){return Object.assign({},f,{status:opt.v});});}}
                  style={{flex:1,padding:"7px 2px",borderRadius:7,border:"2px solid "+(sel?"#4a9eff":"#1e3a8a22"),
                    background:sel?"#1e3a8a22":"#0d0d1a",color:sel?"#4a9eff":"#7090c0",
                    cursor:"pointer",fontSize:10,fontWeight:sel?700:400,textAlign:"center"}}>
                  {opt.l}
                </button>
              );
            })}
          </div>
        </div>
        <div>
        {!showDuplicate && (
          <button onClick={function(){setShowDuplicate(true);}}
            style={{width:"100%",padding:"8px",background:"#0d1a2a",color:"#4a9eff",border:"1px solid #1e3a8a33",borderRadius:8,cursor:"pointer",fontSize:12,marginTop:16,marginBottom:8}}>
            👥 Duplica per altre persone
          </button>
        )}
        {showDuplicate && (
          <div style={{marginTop:12,background:"#0d1a2a",borderRadius:8,padding:12,border:"1px solid #1e3a8a33",marginBottom:8}}>
            <div style={{fontSize:11,color:"#4a9eff",fontWeight:700,marginBottom:8}}>Seleziona persone aggiuntive:</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,maxHeight:200,overflowY:"auto",marginBottom:10}}>
              {PEOPLE.filter(function(p){return p.id!==form.person;}).map(function(p){
                var sel = dupPeople.includes(p.id);
                return (
                  <div key={p.id} onClick={function(){setDupPeople(function(prev){return sel?prev.filter(function(x){return x!==p.id;}):prev.concat([p.id]);});}}
                    style={{padding:"6px 8px",borderRadius:6,border:"2px solid "+(sel?"#4a9eff":"#1e3a8a22"),background:sel?"#1e3a8a22":"#0d0d1a",cursor:"pointer",display:"flex",alignItems:"center",gap:6}}>
                    <div style={{width:22,height:22,borderRadius:"50%",background:sel?"#1e3a8a":"#1a1a2a",display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:800,color:sel?"#fff":"#4a6a9a",flexShrink:0}}>{p.name.charAt(0)}</div>
                    <span style={{fontSize:11,color:sel?"#4a9eff":"#e8e8f0",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{p.name}</span>
                    {sel && <span style={{marginLeft:"auto",color:"#4a9eff",flexShrink:0}}>✓</span>}
                  </div>
                );
              })}
            </div>
            <button onClick={function(){if(dupPeople.length&&onDuplicate) onDuplicate(form,dupPeople); setShowDuplicate(false); setDupPeople([]);}}
              disabled={!dupPeople.length}
              style={{width:"100%",padding:9,background:dupPeople.length?"#14532d":"#222",color:dupPeople.length?"#4caf50":"#555",border:"none",borderRadius:7,cursor:dupPeople.length?"pointer":"not-allowed",fontWeight:700,fontSize:13}}>
              💾 Duplica per {dupPeople.length} {dupPeople.length===1?"persona":"persone"}
            </button>
          </div>
        )}
        <div style={{display:"flex",gap:10,marginTop:12}}>
          <button onClick={function(){ onSave(form); }} style={{flex:1,padding:10,background:"#1e3a8a",color:"#fff",border:"none",borderRadius:8,cursor:"pointer",fontWeight:700,fontSize:14}}>💾 Salva</button>
          <button onClick={onClose} style={{flex:1,padding:10,background:"#0d0d1a",color:"#7090c0",border:"1px solid #333",borderRadius:8,cursor:"pointer"}}>Annulla</button>
          {onDelete && <button onClick={onDelete} style={{padding:"10px 14px",background:"#3a0a0a",color:"#ff6060",border:"1px solid #ff444433",borderRadius:8,cursor:"pointer",fontSize:13}}>🗑️</button>}
        </div>
        </div>
      </div>
    </div>
  );
}

// ── PDFPreview ────────────────────────────────────────────
