                          {b.booking && <span style={{fontFamily:"monospace",color:"#d06000",marginLeft:8}}>#{b.booking}</span>}
                          {b.notes && <div style={{color:"#886600",fontStyle:"italic",marginTop:3}}>📌 {b.notes}</div>}
