                  {b.dep&&<span style={{color:"#7090c0",fontSize:11}}>{b.dep}→{b.arr}</span>}
                  {b.status&&b.status!=="confermata"&&<span style={{fontSize:10,color:b.status==="cancellata"?"#ff6060":"#ffcc00"}}>{b.status==="cancellata"?"❌":"⏳"}</span>}
